/**
 * @fileoverview GridTable Feature — Context menu mixin.
 *
 * Lazy-loaded on first right-click / menu icon click on a column header.
 * Adds a floating menu with sort, pin, autosize, "choose columns", and reset.
 *
 * @module module/GridTable/features/contextmenu
 */

import {
    showColumnContextMenu,
    closeContextMenu,
} from '../view.js';

import {
    bindContextMenuActions,
} from '../events.js';

/**
 * Install the context menu feature onto a GridTable ctx bridge.
 *
 * @param {object} ctx — the shared context bridge
 */
export function installContextMenu(ctx) {
    ctx._contextMenuInstalled = true;

    ctx.showColumnContextMenu = (name, x, y) => showColumnContextMenu(ctx, name, x, y);
    ctx.closeContextMenu      = ()           => closeContextMenu(ctx);
    ctx.bindContextMenuActions = (menu)       => bindContextMenuActions(ctx, menu);
}

export default installContextMenu;
